import React, { useState } from 'react';
import { TestStructure, Question, QuestionType } from '../types';
import { Check, Eye, EyeOff, Printer, RefreshCcw, Home, Award } from 'lucide-react';

interface TestPaperProps {
  test: TestStructure;
  onBack: () => void;
}

const TestPaper: React.FC<TestPaperProps> = ({ test, onBack }) => {
  const [showAnswers, setShowAnswers] = useState(false);

  const getHeaderColor = () => {
    switch (test.colorTheme) {
      case 'green': return 'bg-green-100 border-green-500 text-green-800';
      case 'yellow': return 'bg-yellow-100 border-yellow-500 text-yellow-800';
      case 'red': return 'bg-red-100 border-red-500 text-red-800';
      default: return 'bg-blue-100 border-blue-500 text-blue-800';
    }
  };

  const getBadgeColor = () => {
    switch (test.colorTheme) {
        case 'green': return 'bg-green-500';
        case 'yellow': return 'bg-yellow-500';
        case 'red': return 'bg-red-500';
        default: return 'bg-blue-500';
    }
  }

  const handlePrint = () => {
    window.print();
  };

  const renderSection = (title: string, questions: Question[]) => {
    if (!questions || questions.length === 0) return null;
    return (
      <div className="mb-8 print-break-inside-avoid">
        <h3 className="text-xl font-bold mb-4 border-b-2 border-gray-300 pb-2 uppercase text-gray-700 flex items-center gap-2">
          {title}
        </h3>
        <div className="space-y-6">
          {questions.map((q, idx) => (
            <div key={q.id} className="bg-white p-4 rounded-lg shadow-sm border border-gray-100 print:shadow-none print:border-0 print:p-0 print:mb-4 break-inside-avoid">
              <div className="flex gap-3">
                <span className="font-bold text-gray-500 print:text-black">Câu {idx + 1}.</span>
                <div className="flex-1">
                    <div className="flex justify-between items-start">
                         <p className="text-lg font-medium text-gray-800 mb-2 whitespace-pre-line print:text-black">
                            {q.image && <span className="mr-2 text-2xl align-middle">{q.image}</span>}
                            {q.questionText}
                        </p>
                        <span className="text-xs font-bold bg-gray-100 text-gray-500 px-2 py-1 rounded print:hidden">
                            {q.points} điểm
                        </span>
                    </div>

                  {q.type === QuestionType.MULTIPLE_CHOICE && q.options && (
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-2">
                      {q.options.map((opt, i) => (
                        <div key={i} className="flex items-center gap-2 p-2 border rounded-md hover:bg-gray-50 print:border-none print:p-0">
                          <span className="w-6 h-6 flex items-center justify-center rounded-full border border-gray-400 text-sm font-bold print:border-black">
                            {String.fromCharCode(65 + i)}
                          </span>
                          <span className="print:text-black">{opt}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {q.type === QuestionType.ESSAY && (
                     <div className="mt-4 border-b border-gray-300 border-dashed h-16 w-full print:block hidden"></div>
                  )}

                  {/* Answer Section */}
                  {showAnswers && (
                    <div className="mt-4 p-3 bg-green-50 rounded border border-green-200 text-green-800 text-sm print:block print:bg-transparent print:border-0 print:text-gray-500 print:mt-1 print:p-0 print:text-xs">
                       <p className="font-bold flex items-center gap-1">
                        <Check size={16} /> Đáp án: {q.correctAnswer}
                       </p>
                       {q.explanation && (
                         <p className="text-gray-600 mt-1 italic print:text-xs">💡 {q.explanation}</p>
                       )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Control Bar (Hidden on Print) */}
      <div className="sticky top-0 z-50 bg-white shadow-md p-4 no-print flex justify-between items-center gap-4">
        <button onClick={onBack} className="flex items-center gap-2 text-gray-600 hover:text-blue-600 font-medium">
          <Home size={20} /> <span className="hidden sm:inline">Quay lại</span>
        </button>

        <div className="flex gap-3">
          <button 
            onClick={() => setShowAnswers(!showAnswers)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg font-bold transition-colors ${showAnswers ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
          >
            {showAnswers ? <EyeOff size={18} /> : <Eye size={18} />}
            <span className="hidden sm:inline">{showAnswers ? 'Ẩn Đáp Án' : 'Xem Đáp Án'}</span>
          </button>

          <button 
            onClick={handlePrint}
            className="flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white font-bold hover:bg-blue-700 transition-colors shadow-sm"
          >
            <Printer size={18} />
            <span className="hidden sm:inline">In Đề</span>
          </button>
        </div>
      </div>

      {/* Paper Content */}
      <div className="max-w-4xl mx-auto p-8 bg-white shadow-xl mt-6 min-h-[29.7cm] print:shadow-none print:mt-0 print:p-0">

        {/* Header */}
        <div className={`border-4 rounded-xl p-6 mb-8 text-center ${getHeaderColor()} print:border-black print:bg-white print:text-black`}>
            <div className="flex justify-between items-start mb-2 text-sm uppercase tracking-wider opacity-70">
                <span>Trường: ..............................</span>
                <span>Lớp: 1.....</span>
            </div>
            <div className="flex justify-between items-start mb-6 text-sm uppercase tracking-wider opacity-70">
                <span>Họ và tên: ..........................</span>
                <span>Ngày: ...../...../..........</span>
            </div>

            <h1 className="text-3xl font-bold uppercase mb-2 font-hand">{test.title}</h1>
            <p className="text-lg opacity-90 font-medium">{test.subTitle}</p>

            <div className="mt-4 flex justify-center gap-8 text-sm font-bold no-print">
                 <span className="bg-white/50 px-3 py-1 rounded-full">Thời gian: 40 phút</span>
                 <span className="bg-white/50 px-3 py-1 rounded-full">Môn: Toán (Cánh Diều)</span>
            </div>
            <div className="mt-4 hidden print:block text-center text-sm italic">
                (Thời gian làm bài: 40 phút)
            </div>
        </div>

        {/* Content */}
        {renderSection('Phần 1: Trắc Nghiệm', test.questions.part1)}
        {renderSection('Phần 2: Tự Luận', test.questions.part2)}
        {renderSection('Phần 3: Toán Tư Duy', test.questions.part3)}

        {/* Game Section (Optional) */}
        {test.questions.part4.length > 0 && (
            <div className="mt-8 pt-8 border-t-4 border-dashed border-gray-200 print:break-before-page">
                <div className="flex items-center gap-3 mb-4">
                     <span className="text-3xl animate-bounce">🎪</span>
                     <h3 className="text-xl font-bold uppercase text-purple-600 font-hand">Góc Đố Vui - Giải trí</h3>
                </div>
                 <div className="bg-purple-50 p-6 rounded-xl border border-purple-200">
                    {test.questions.part4.map((q, i) => (
                        <div key={q.id}>
                            <p className="font-bold text-lg mb-2 text-purple-900">{q.image} {q.questionText}</p>
                            {showAnswers ? (
                                <p className="text-purple-600 font-bold">👉 {q.correctAnswer}</p>
                            ) : (
                                <p className="text-gray-400 italic text-sm">(Xem đáp án để biết kết quả)</p>
                            )}
                        </div>
                    ))}
                 </div>
            </div>
        )}

        {/* Footer Advice */}
        <div className="mt-12 p-4 bg-gray-50 rounded-lg border border-gray-200 text-sm text-gray-600 print:border-black print:bg-white print:mt-8">
            <h4 className="font-bold mb-2 flex items-center gap-2">
                <Award size={16} className="text-yellow-500"/> Gợi ý chấm điểm & Nhận xét:
            </h4>
            <p><strong>Dành cho phụ huynh:</strong> {test.advice}</p>
            <div className="mt-4 h-20 border border-gray-300 rounded p-2 hidden print:block">
                <span className="text-xs uppercase text-gray-400">Lời phê của giáo viên:</span>
            </div>
        </div>

        <div className="mt-8 text-center text-gray-400 text-xs print:mt-12">
            Đề bài được biên soạn theo chương trình Cánh Diều - Lớp 1 (Kỳ 2).
        </div>

      </div>
    </div>
  );
};

