interface TestPaperProps {
  test: TestStructure;
  onBack: () => void;
  onRegenerate?: () => void;
}

const TestPaper: React.FC<TestPaperProps> = ({ test, onBack, onRegenerate }) => {
  const [userAnswers, setUserAnswers] = useState<Record<string, string>>({});
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [mcqScore, setMcqScore] = useState(0);
  const [totalMcqPoints, setTotalMcqPoints] = useState(0);

  // Reset state when test changes (including when regenerated with same ID prefix but different content)
  useEffect(() => {
    setUserAnswers({});
    setIsSubmitted(false);
    setMcqScore(0);
    setTotalMcqPoints(0);
  }, [test.id]);

  const getHeaderColor = () => {
    switch (test.colorTheme) {
      case 'green': return 'bg-green-100 border-green-500 text-green-800';
      case 'yellow': return 'bg-yellow-100 border-yellow-500 text-yellow-800';
      case 'red': return 'bg-red-100 border-red-500 text-red-800';
      default: return 'bg-blue-100 border-blue-500 text-blue-800';
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const handleShuffle = () => {
     if (isSubmitted) {
        if (window.confirm("Bạn muốn tạo đề mới? Kết quả hiện tại sẽ bị xóa.")) {
             if(onRegenerate) onRegenerate();
        }
     } else {
         // If in progress, ask for confirmation
         const hasAnswers = Object.keys(userAnswers).length > 0;
         if (!hasAnswers || window.confirm("Bạn đang làm dở. Bạn có chắc muốn đổi đề mới không?")) {
             if(onRegenerate) onRegenerate();
         }
     }
  };

  const handleAnswerChange = (questionId: string, value: string) => {
    if (isSubmitted) return; // Prevent changes after submission
    setUserAnswers(prev => ({
      ...prev,
      [questionId]: value
    }));
  };

  const handleSubmit = () => {
    let score = 0;
    let totalPoints = 0;

    // Calculate MCQ score
    [...test.questions.part1, ...test.questions.part4].forEach(q => {
      if (q.type === QuestionType.MULTIPLE_CHOICE || q.type === QuestionType.GAME) {
         // Logic checks handled below inside specific array iteration if needed, 
         // but general scoring is usually Part 1.
      }
    });

    test.questions.part1.forEach(q => {
       if (q.type === QuestionType.MULTIPLE_CHOICE) {
           totalPoints += q.points;
           if (userAnswers[q.id] === q.correctAnswer) {
               score += q.points;
           }
       }
    });

    setMcqScore(score);
    setTotalMcqPoints(totalPoints);
    setIsSubmitted(true);

    // Scroll to top
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleRetry = () => {
    const confirmReset = window.confirm("Bạn có chắc muốn làm lại bài không? Mọi câu trả lời sẽ bị xóa.");
